export const getGetResolutionsUrl = (buildingId: number,
    params?: GetResolutionsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/buildings/${buildingId}/resolutions?${stringifiedParams}` : `/api/buildings/${buildingId}/resolutions`
}

